<template>
  <div class="page-card">
    <h2>🐩 属于你的小狗</h2>
    <div class="carousel-area">
      <!-- 主图展示区：只显示一张图片，强制统一尺寸 -->
      <div class="image-preview">
        <img 
          v-if="!selectedDog" 
          :src="currentLoopImage" 
          :key="currentLoopImage" 
          alt="轮播小狗"
          class="uniform-image"
        >
        <img 
          v-else 
          :src="selectedDog" 
          alt="你的小狗"
          class="uniform-image"
        >
      </div>

      <!-- 按钮区域：根据状态显示不同按钮，但都在当前页操作 -->
      <button v-if="!selectedDog" class="btn small" @click="pickRandomDog">选择 🎲</button>
      <button v-else class="btn small" @click="resetLottery">🐾 再抽一次</button>
    </div>

    <!-- 抽取成功提示 -->
    <transition name="fade">
      <div v-if="selectedDog" class="result-message">
        ✨ 恭喜你抽到了属于你的小狗！ ✨
      </div>
    </transition>
  </div>
</template>

<script>
export default {
  name: 'LotteryPage',
  props: {
    dogImages: {
      type: Array,
      required: true
    }
  },
  data() {
    return {
      currentLoopImage: this.dogImages[0], // 当前显示的图片（轮播或结果）
      selectedDog: null,                    // 抽中的图片
      loopInterval: null                     // 轮播定时器
    };
  },
  mounted() {
    this.startLoop(); // 开始轮播
  },
  methods: {
    // 开始轮播
    startLoop() {
      // 停止已有定时器避免冲突
      this.stopLoop();
      
      let index = this.dogImages.indexOf(this.currentLoopImage);
      if (index === -1) index = 0;

      this.loopInterval = setInterval(() => {
        if (!this.selectedDog) {
          index = (index + 1) % this.dogImages.length;
          this.currentLoopImage = this.dogImages[index];
        }
      }, 100);
    },
    // 随机抽取
    pickRandomDog() {
      if (this.selectedDog) return;

      const randomIndex = Math.floor(Math.random() * this.dogImages.length);
      const picked = this.dogImages[randomIndex];
      
      this.selectedDog = picked;
      this.currentLoopImage = picked; // 立即显示抽中图片
      this.stopLoop();
    },
    // 重置抽奖 - 仅重置当前页状态，不跳转
    resetLottery() {
      this.selectedDog = null;                    // 清空抽中结果
      this.currentLoopImage = this.dogImages[0];  // 重置为第一张
      this.startLoop();                            // 重新开始轮播
      // 注意：不再发射 'reset' 事件到父组件，避免父组件切换页面
    },
    // 停止轮播
    stopLoop() {
      if (this.loopInterval) {
        clearInterval(this.loopInterval);
        this.loopInterval = null;
      }
    }
  },
  beforeDestroy() {
    this.stopLoop();
  }
};
</script>

<style scoped>
/* 整体卡片样式 */
.page-card {
  background: #ffffffdd;
  border-radius: 40px;
  padding: 32px 24px;
  text-align: center;
  box-shadow: inset 0 2px 8px rgba(255,255,255,0.8), 0 12px 28px -8px #ba8f3f;
}

h2 {
  color: #4a3729;
  font-size: 2rem;
  font-weight: 700;
  margin-bottom: 24px;
  text-shadow: 2px 2px 0 #ffe2a3;
}

/* 抽奖区域 */
.carousel-area {
  background: #fbeed8;
  border-radius: 48px;
  padding: 32px 20px;
  margin: 20px 0 28px;
  border: 4px dashed #edb378;
}

/* 图片预览容器 - 固定宽高，保证所有图片显示区域一致 */
.image-preview {
  width: 280px;           /* 固定宽度 */
  height: 280px;          /* 固定高度 */
  margin: 0 auto 28px;
  border-radius: 50%;     /* 圆形蒙版 */
  background: #ead3b0;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;       /* 隐藏溢出的图片部分 */
  box-shadow: 0 20px 25px -8px #b37b44;
  border: 6px solid #fef7d2;
}

/* 统一图片尺寸：强制所有图片以相同方式填充容器 */
.uniform-image {
  width: 100%;
  height: 100%;
  object-fit: cover;      /* 覆盖模式，保证所有图片填满容器且比例不变 */
  display: block;
}

/* 按钮样式 */
.btn {
  background: #ffb347;
  border: none;
  border-radius: 60px;
  padding: 16px 42px;
  font-size: 1.8rem;
  font-weight: bold;
  color: #2e1f13;
  box-shadow: 0 9px 0 #9f5f2a, 0 10px 20px rgba(0,0,0,0.2);
  cursor: pointer;
  transition: all 0.08s linear;
  margin: 8px 0 16px;
  border: 2px solid #ffe39c;
}

.btn.small {
  font-size: 1.5rem;
  padding: 12px 36px;
}

.btn:active {
  transform: translateY(7px);
  box-shadow: 0 2px 0 #9f5f2a, 0 5px 12px rgba(0,0,0,0.2);
}

/* 恭喜消息 */
.result-message {
  background: #b3d9b0;
  border-radius: 40px;
  padding: 20px;
  margin: 20px 0 0;
  font-size: 1.8rem;
  font-weight: bold;
  color: #274e13;
  border: 3px solid #fceb9c;
  box-shadow: 0 6px 0 #6b8c5c;
}

/* 淡入淡出动画 */
.fade-enter-active, .fade-leave-active {
  transition: opacity 0.4s;
}
.fade-enter, .fade-leave-to {
  opacity: 0;
}
</style>